import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyCustomTabs, headerActions, headerStrings, breadCrumbActions, mainStageHeaderAction, mainStageHeaderStrings } from '../../includes';
import { TimeTableSheet } from './TimeTableSheet';
import { TimeTablePeriods } from './TimeTablePeriods/TimeTablePeriods';
import { TimeTableHeaderComponent } from './TimeTableHeaderComponent';
import { timeTableActions } from './actions';
import { routeNamesSchool } from '../routeNames';

const style = theme => ({
    root: {
    }
})
class _TimeTable extends Component {
    constructor(props) {
        super(props);
        this.state = {
            tabValue : null
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "SCHEDULES (TIME TABLE)"
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesSchool.dashboard},
            {name : "Subjects", path : routeNamesSchool.subjects},
            {name : "Time Table", path : ""}
        ])(dispatch)
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [
                TimeTableHeaderComponent
            ]
        })(dispatch);
        this.setComponentContext = this.setComponentContext.bind(this);
    }
    
    tabValueChangeHandler = tabValue => {
        this.setState({tabValue});
        timeTableActions.setTabValue(tabValue)(this.props.dispatch);
    }
    setComponentContext = context => {
        const {dispatch} = this.props;
        timeTableActions.setTabComponent(
            context
        )(dispatch);
    }
    render() {
        const {classes} = this.props;
        const { tabValue } = this.state;
        return (
            <div className={classes.root}>
                <MyCustomTabs
                    position="sticky"
                    tabs={{
                        timeTable : "Time Table",
                        period : "Periods",
                    }}
                    getInitialTabValue={this.tabValueChangeHandler.bind(this)}
                    />
                {tabValue === "timeTable" && <TimeTableSheet 
                    getContext={this.setComponentContext}/>}
                {tabValue === "period" && <TimeTablePeriods
                    getContext={this.setComponentContext}/>}
            </div>
        );
    }
}


_TimeTable.propTypes = {
    classes : PropTypes.object.isRequired
};
export const TimeTable = connect()(withStyles(style)(_TimeTable));
export {TimeTable as default};