import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { 
   MyTable, HighlightedInfo 
} from '../../../includes';
import { days } from '../../../../utils';
import { TableCell } from '@material-ui/core';
import { TimeTableSubjectSelectHandle } from '../TimeTableSubjectSelectHandle';
import { SchoolDay } from '../SchoolDay';
import { timeTableActions, timeTableStrings } from '../config';

const levelTable = [
    {
        classId : 1,
        class : {
            name : "Primary 1 B",
        },
        timeTable : [
            {
                _id : 1,
                day : "Mondays",
                time : [
                    {formatId : 1, sessionSubjectId : 1},
                    {formatId : 2, sessionSubjectId : 2}
                ]
            },
            {
                _id : 1,
                day : "Tuesdays",
                time : [
                    {formatId : 1, sessionSubjectId : 1},
                    {formatId : 2, sessionSubjectId : 2}
                ]
            },
        ]
    },
    {
        classId : 2,
        class : {
            name : "Primary 1 C",
        },
        timeTable : [
            {
                _id : 1,
                day : "Mondays",
                time : [
                    {formatId : 1, sessionSubjectId : 1},
                    {formatId : 2, sessionSubjectId : 2}
                ]
            },
            {
                _id : 1,
                day : "Tuesdays",
                time : [
                    {formatId : 1, sessionSubjectId : 1},
                    {formatId : 2, sessionSubjectId : 2}
                ]
            },
        ]
    },
]
const style = theme => ({
    root: {
        marginTop : 30
    }
})
class _TimeTableSheet extends Component {
    constructor(props) {
        super(props);
        this.state = {
            levelTable,
            schoolDay : "Monday"
        }
        if(props.getContext)
            props.getContext(this);
        this.setSchoolDay = this.setSchoolDay.bind(this);
    }
    componentWillUnmount() {        
        const {
            dispatch,
            [timeTableStrings.timeTableEditMode] : editMode
        } = this.props;
        if(editMode) 
            timeTableActions.setTimeTableEditeMode(false)(dispatch);
    }
    
    generateTableHeader = timeFormat => {
        let header = ["Classes"];
        let dataMap = ["class"];
        if(timeFormat) for (let i = 0; i < timeFormat.length; i++) {
            const time = timeFormat[i];
            header.push(time.start+"-"+time.end);
            dataMap.push(time._id);
        }
        return {header, dataMap};
    }
    generateData = (levelTable, day="Monday") => {
        let data = [];
        if(levelTable) for (let i = 0; i < levelTable.length; i++) {
            const timeTableInfo = levelTable[i];
            const {timeTable, classId, class : classInfo} = timeTableInfo;
            let dataInfo = { classId, class : classInfo.name };
            for (let j = 0; j < timeTable.length; j++) {
                const timeInfo = timeTable[j];
                const {day : classDay, time} = timeInfo;
                if(day === classDay && time){
                    for (let k = 0; k < time.length; k++) {
                        const schedule = time[k];
                        // dataInfo.sessionSubjectId = schedule.sessionSubjectId;
                        dataInfo[schedule.formatId] = schedule.sessionSubjectId; //"English"; //get the subject infos
                    }
                }
            }
            data.push(dataInfo);
        }
        return data;
    }
    getSubjectNames(subjectId){
        const subjects = {
            1 : "English",
            2 : "Maths",
            "none" : "None"
        }
        return subjects[subjectId];
    }
    cellMapFormat = (editMode, subjects) => ({row, cellMap})=>{
        if(editMode && cellMap !== "class") 
            return <TableCell>
                <TimeTableSubjectSelectHandle 
                    row={row} cellMap={cellMap}
                    subjects={subjects || []}
                    value={this.getSubjectNames(row[cellMap])}
                    selectionHandler={this.setTimeTableSubject.bind(this)}/>
            </TableCell>        
        else if(cellMap === "class") return <TableCell>
                {row[cellMap]}
            </TableCell> 
        else return <TableCell>
                {this.getSubjectNames(row[cellMap])}
            </TableCell>
        
    }
    setTimeTableSubject = (row, formatId) => subjectOption => {
        let {levelTable, schoolDay} = this.state;
        const newTimeSubject = {formatId, sessionSubjectId: subjectOption._id};
        console.log(row, "formatId===", formatId, schoolDay, levelTable);
        if(levelTable){
            let levelTableFilter = levelTable.getFirstObjectByPropValue("classId", row.classId);
            if(levelTableFilter){
                let {item : levelTableItem, index : levelTableIndex} = levelTableFilter;
                if(levelTableItem){
                    const {timeTable} = levelTableItem;
                    if(timeTable){
                        let timeTableFilter = timeTable.getFirstObjectByPropValue("day", schoolDay);
                        if(timeTableFilter){
                            let {item : timeTableItem, index : classIndex} = timeTableFilter;
                            if(timeTableItem){
                                let time = timeTableItem.time;
                                if(time){
                                    const timeFilter = time.getFirstObjectByPropValue("formatId", formatId);
                                    if(timeFilter){
                                        let {item : timeItem, index : timeIndex} = timeFilter;
                                        time[timeIndex] = {...timeItem, sessionSubjectId : subjectOption._id};
                                    }else{
                                        time.push(newTimeSubject)
                                    }
                                }else{
                                    timeTableItem.time = [newTimeSubject];
                                }
                            }
                        }else {
                            timeTable.push({
                                day : schoolDay,
                                time : [newTimeSubject]
                            })
                        }

                    }
                }
            }
            levelTable = [...levelTable];
            this.setState({levelTable});
        }
    }
    
    setSchoolDay = dayIndex => this.setState({schoolDay : days[dayIndex]});
    render() {
        const {
            classes,
            [timeTableStrings.timeTableEditMode] : timeTableEditMode,
            [timeTableStrings.timeTableDurationFormat] : timeTableFormat,
            [timeTableStrings.selectedLevel] : selectedLevel, 
            [timeTableStrings.selectedTerm] : selectedTerm, 
            [timeTableStrings.subjects] : subjects
        } = this.props;
        const {levelTable, schoolDay} = this.state;
        /**
         *  the header is derived within the generate and the table header (time)
         *  id form part of the data... check the muiltheader of the mytable
         */
        return (
            <div className={classes.root}>
                {selectedLevel && selectedTerm ?
                    (timeTableFormat && <div>
                        <SchoolDay
                            days={days}
                            getInitialDayIndex={this.setSchoolDay}
                            setSuperDayIndex={this.setSchoolDay}/>
                        <MyTable
                            {...this.generateTableHeader(timeTableFormat)}
                            data={this.generateData(levelTable, schoolDay)}
                            CellMap={this.cellMapFormat(timeTableEditMode, subjects)}
                            />
                    </div>) :
                    <HighlightedInfo>
                        Selected the level and term of which time table you want to view
                    </HighlightedInfo>}
            </div>
        );
    }
}


_TimeTableSheet.propTypes = {
    classes : PropTypes.object.isRequired,
    goBack : PropTypes.func,
    getContext : PropTypes.func,
};

const mapStateToProps = ({timeTableReducer}) => ({
    [timeTableStrings.selectedLevel] : timeTableReducer[timeTableStrings.selectedLevel],
    [timeTableStrings.selectedTerm] : timeTableReducer[timeTableStrings.selectedTerm],
    [timeTableStrings.timeTableEditMode] : timeTableReducer[timeTableStrings.timeTableEditMode],
    [timeTableStrings.timeTableDurationFormat] : timeTableReducer[timeTableStrings.timeTableDurationFormat],
    [timeTableStrings.subjects] : timeTableReducer[timeTableStrings.subjects],
})


export const TimeTableSheet = connect(mapStateToProps)(withStyles(style)(_TimeTableSheet));
export {TimeTableSheet as default};