import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyPopupMenu } from '../../includes';


const style = theme => ({
    root: {
    }
})
class _TimeTableSubjectSelectHandle extends Component {
    render() {
        const {
            classes, row, cellMap, selectionHandler, value,
            subjects
        } = this.props;
        return (
            <div className={classes.root}>
                <MyPopupMenu
                    buttonName={"subject-"+row.sessionSubjectId}
                    buttonValue={value || "Subject"}
                    options={[...subjects,
                        {name : "None", _id : "none"},
                    ]}
                    optionValueProp="_id"
                    optionNameProp="name"
                    optionClickCallback={selectionHandler(row, cellMap)}/>
            </div>
        );
    }
}


_TimeTableSubjectSelectHandle.propTypes = {
    classes : PropTypes.object.isRequired,
    row : PropTypes.object,
    cellMap : PropTypes.any,
    selectionHandler : PropTypes.func,
    subjects : PropTypes.array,
};

export const TimeTableSubjectSelectHandle = connect()(withStyles(style)(_TimeTableSubjectSelectHandle));