import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { timeTableActions } from '../actions';
import { timeTableStrings } from '../config';
import { HighlightedInfo, MyTable, EditableCellMapFormat } from '../../../includes';
import { Switch, TextField } from '@material-ui/core';


const style = theme => ({
    root: {
        marginTop : 20
    }
})
class _TimeTablePeriods extends Component {
    constructor(props) {
        super(props);
        this.state = {
            selectedLevel : null,
            selectedTerm : null,
        }
        if(props.getContext)
            props.getContext(this);
    }
    componentWillUnmount() {
        const {
            dispatch,
            [timeTableStrings.timeTableEditMode] : editMode
        } = this.props;
        if(editMode) 
            timeTableActions.setTimeTableEditeMode(false)(dispatch);
    }
    static getDerivedStateFromProps(props, state) {
        const {
            [timeTableStrings.selectedLevel] : selectedLevel,
            [timeTableStrings.selectedTerm] : selectedTerm,
            dispatch
        } = props;
        if(selectedLevel && JSON.stringify(selectedLevel) !== JSON.stringify(state.selectedLevel)){
            state.selectedLevel = selectedLevel;
        }
        if(selectedTerm && JSON.stringify(selectedTerm) !== JSON.stringify(state.selectedTerm)){
            state.selectedTerm = selectedTerm;
            timeTableActions.getTimeTableDurationFormat(
                selectedLevel._id,
                selectedTerm._id, 
                (done, result)=>{
                    if(done)  
                        state.timeTableDurations = result;
                }
            )(dispatch);
        }
        
        return state
    }
    
    componentDidMount() {
        timeTableActions.getTimeTableDurationFormat()
    }
    cellMapFormat = superProps => props => <EditableCellMapFormat {...props} {...superProps}/>;
    tableCellContentView = (editing, {row, cellMap}) => {
        if(editing){
            switch(cellMap){
                case "break" : return <Switch size="small"/>;
                default : return <TextField
                    type="time"
                    defaultValue={new Date().toLocaleTimeString()}/>;
            }
        }else{
            switch(cellMap){
                case  "break" : 
                    return <Switch size="small"/>;
                default : return row[cellMap]
            }
        }
    }
    render() {
        let {
            classes,
            [timeTableStrings.timeTableDurationFormat] : tableDurations,
            [timeTableStrings.selectedLevel] : selectedLevel,
            [timeTableStrings.selectedTerm] : selectedTerm,
            [timeTableStrings.timeTableEditMode] : timeTableEditMode
        } = this.props;
        let header = ["ID", "Start", "End", "Break"];
        let dataMap = ["_id", "start", "end", "break"];
        console.log(this.props);
        if(timeTableEditMode){
            tableDurations = tableDurations ? 
                [...tableDurations.map(item=>({
                    ...item, 
                    editable : true, 
                    delible : true
                })), {new : true}] : 
                [{new : true}];
            header = [...header,"Actions"];
            dataMap = [...dataMap, "action"];
        }
        return (
            <div className={classes.root}>
                {selectedLevel && selectedTerm ? 
                    <div>
                        <HighlightedInfo type="primary" closable>
                            This periods will appear as the headings of the schedule table (Time Table),
                            only the start and end time will be used in the time table
                        </HighlightedInfo>
                        <MyTable
                            header={header}
                            dataMap={dataMap}
                            data={tableDurations}                            
                            CellMap={this.cellMapFormat({
                                skipEdit : ['_id'],
                                tableCellContentView : this.tableCellContentView.bind(this)
                            })}/>
                    </div> : 
                    <HighlightedInfo>
                        Select the level and term of the table periods (use the menu buttons above)
                    </HighlightedInfo>}
            </div>
        );
    }
}


_TimeTablePeriods.propTypes = {
    classes : PropTypes.object.isRequired,
    getContext : PropTypes.func,
};

const mapStateToProps = ({timeTableReducer}) => ({
    [timeTableStrings.selectedLevel] : timeTableReducer[timeTableStrings.selectedLevel],
    [timeTableStrings.selectedTerm] : timeTableReducer[timeTableStrings.selectedTerm],
    [timeTableStrings.timeTableEditMode] : timeTableReducer[timeTableStrings.timeTableEditMode],
    [timeTableStrings.timeTableDurationFormat] : timeTableReducer[timeTableStrings.timeTableDurationFormat],
})


export const TimeTablePeriods = connect(mapStateToProps)(withStyles(style)(_TimeTablePeriods));