import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { FormControl, Button } from '@material-ui/core';
import { colors } from '../../../utils';
import { MyPopupMenu } from '../../includes';
import { timeTableStrings, timeTableActions } from './config';
const style = theme => ({
    root: {
    },
    formControl : {
        margin : 10
    }
})
class _TimeTableHeaderComponent extends Component {
    constructor(props) {
        super(props);
        const {dispatch} = props;
        timeTableActions.getLevels()(dispatch);
    }
    
    setTimeTableEditMode(){
        const {
            [timeTableStrings.timeTableEditMode] : timeTableEditMode,
            [timeTableStrings.tabValue] : tabValue,
            componentRef,
            dispatch
        } = this.props;
        timeTableActions.setTimeTableEditeMode(!Boolean(timeTableEditMode))(dispatch);
        /**
         * TO DO
         */
        if(timeTableEditMode){
            //save
            if(tabValue === "period"){

            }else{

            }
        }
    }
    setSelectedLevel = level => {
        const {dispatch} = this.props;
        timeTableActions.setSelectedLevel(level)(dispatch);
        timeTableActions.setSelectedTerm(null)(dispatch);
        timeTableActions.getTerms(level._id)(dispatch);
    }
    setSelectedTerm = term => {
        const {
            dispatch, 
            [timeTableStrings.selectedLevel] : selectedLevel,
            [timeTableStrings.selectedTerm] : selectedTerm
        } = this.props;
        timeTableActions.setSelectedTerm(term)(dispatch);
        /**
         * TO DO    
         *  get the selected level and term id
         */
        timeTableActions.getTimeTableDurationFormat(1, 1)(dispatch);
        timeTableActions.getSubjects(1,1)(dispatch);
    }
    cancelEdit = () => {
        const {dispatch} = this.props;
        timeTableActions.setTimeTableEditeMode(false)(dispatch);
    }
    render() {
        const {
            classes,
            [timeTableStrings.timeTableEditMode] : timeTableEditMode,
            [timeTableStrings.selectedLevel] : selectedLevel,
            [timeTableStrings.selectedTerm] : selectedTerm,
            [timeTableStrings.levels] : levels,
            [timeTableStrings.terms] : terms,
        } = this.props;
        return (
            <div className={classes.root}>
                <FormControl>
                    <MyPopupMenu
                        buttonValue={(selectedLevel && selectedLevel.name) || "Levels"}
                        buttonName="levels"
                        optionNameProp="name"
                        optionValueProp="_id"
                        options={levels}
                        optionClickCallback={this.setSelectedLevel.bind(this)}/>
                </FormControl>
                <FormControl>
                    <MyPopupMenu
                        buttonValue={(selectedTerm && selectedTerm.name) || "Terms"}
                        buttonName="terms"
                        optionNameProp="name"
                        optionValueProp="_id"
                        options={terms}
                        optionClickCallback={this.setSelectedTerm.bind(this)}/>
                </FormControl>
                {selectedLevel && selectedTerm && 
                <FormControl 
                    className={classes.formControl}>
                    <Button 
                        variant="contained" style={{backgroundColor:colors.secondary}}
                        onClick={this.setTimeTableEditMode.bind(this)}>
                            {timeTableEditMode ? "Save" : "Edit"}
                        </Button>
                </FormControl>}
                {timeTableEditMode && 
                    <FormControl className={classes.formControl}>
                        <Button 
                        color="secondary"
                        onClick={this.cancelEdit.bind(this)}>Cancel</Button>
                    </FormControl>}
            </div>
        );
    }
}


_TimeTableHeaderComponent.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({timeTableReducer}) => ({
    [timeTableStrings.timeTableEditMode] : timeTableReducer[timeTableStrings.timeTableEditMode],
    [timeTableStrings.selectedLevel] : timeTableReducer[timeTableStrings.selectedLevel],
    [timeTableStrings.selectedTerm] : timeTableReducer[timeTableStrings.selectedTerm],
    [timeTableStrings.terms] : timeTableReducer[timeTableStrings.terms],
    [timeTableStrings.levels] : timeTableReducer[timeTableStrings.levels],
    [timeTableStrings.tabValue] : timeTableReducer[timeTableStrings.tabValue],
    [timeTableStrings.tabComponent] : timeTableReducer[timeTableStrings.tabComponent],
})


export const TimeTableHeaderComponent = connect(mapStateToProps)(withStyles(style)(_TimeTableHeaderComponent));